const profiles = $('Split Into Individual Profiles').all();
const sheetRows = $('Read Emails from Google Sheet').all().map(i => i.json);
const emailMap = {};
for (const row of sheetRows) {
  const urlKey = Object.keys(row).find(k => k.toLowerCase().includes('profile') && k.toLowerCase().includes('url'));
  const emailKey = Object.keys(row).find(k => k.toLowerCase().includes('email') && k.toLowerCase() !== 'email status');
  const url = (urlKey ? row[urlKey] : '').trim();
  const email = (emailKey ? row[emailKey] : '').trim();
  if (url && email && email.includes('@') && !email.toLowerCase().includes('restricted')) {
    emailMap[url.toLowerCase()] = email;
  }
}
const results = [];
for (const item of profiles) {
  const p = { ...item.json };
  const currentEmail = (p.email || '').toLowerCase();
  const isRestricted = !currentEmail || !currentEmail.includes('@') || currentEmail.includes('restricted');
  if (isRestricted) {
    const url = (p.url || p.linkedin_url || '').toLowerCase();
    const sheetEmail = emailMap[url];
    if (sheetEmail) { p.email = sheetEmail; p.email_source = 'google_sheet'; }
  }
  // FILTER: skip invalid leads
  const finalEmail = (p.email || '').trim();
  if (!finalEmail.includes('@')) continue;
  if (finalEmail.toLowerCase().includes('restricted')) continue;
  const status = (p.status || '').toUpperCase();
  if (status === 'STOPPED' || status === 'REPLIED') continue;

  results.push({ json: p });
}
return results;

const existingLeads = $input.all().map(i => i.json);
const flat = Array.isArray(existingLeads[0]) ? existingLeads[0] : existingLeads;
const existingEmails = new Set(flat.map(l => (l.email || '').toLowerCase()));
const existingUrls = new Set(flat.map(l => (l.linkedin_url || l.url || '').toLowerCase()));

// Get scraped profiles from the EARLIER node (not $input)
const currentItems = $('Fill Missing Emails from Sheet').all();
const results = [];

for (const item of currentItems) {
  console.log(item)
  const email = (item.json.email || '').toLowerCase();
  const url = (item.json.url || '').toLowerCase();
  const status = (item.json.status || 'NEW').toUpperCase();
  const isNew = !existingEmails.has(email) && !existingUrls.has(url);
  const isIgnored = status === 'IGNORED';
  const isNewStatus = status === 'NEW' || status === 'ACTIVE';
  if (isNew || isIgnored || isNewStatus) {
    results.push(item);
  }
}
return results;

const item = $input.first().json;
const summary = [
  `Name: ${item.name || 'Unknown'}`,
  `Role: ${item.role || 'Professional'}`,
  `Company: ${item.company || 'their company'}`,
  `Headline: ${item.headline || ''}`,
  `About: ${(item.about || '').substring(0, 300)}`,
  `Recent Activity: ${(item.recent_activity || []).slice(0, 2).join('; ')}`
].join('\n');
return [{ json: { ...item, ai_summary: summary } }];

const BACKEND_URL = 'https://email-drip-campaign-hpo2.onrender.com';

// 🔥 GET GEMINI RESPONSE
const aiRaw = $('AI Generate Personalized Email').first().json.content?.parts?.[0]?.text || '';

let parsed = {};

try {
  parsed = JSON.parse(aiRaw);
} catch (e) {
  console.log("JSON parse failed, using raw text");
}

// ✅ FINAL VALUES
const subject = parsed.subject || 'Quick question';
const body = parsed.body || aiRaw;

// tracking
const trackingId = 'trk_' + Date.now() + '_' + Math.random().toString(36).substring(2, 10);

// pixel
const trackingPixel = `<img src="${BACKEND_URL}/api/tracking/track/${trackingId}" width="1" height="1" style="display:none;" />`;

// convert links
const urlRegex = /(https?:\/\/[^\s<>\"]+)/g;

let emailBody = body.replace(urlRegex, (url) => {
  if (url.includes(BACKEND_URL)) return url;
  return `${BACKEND_URL}/api/tracking/click/${trackingId}?redirect_url=${encodeURIComponent(url)}`;
});

emailBody = emailBody.replace(/\n/g, '<br>');

return [{
  json: {
    tracking_id: trackingId,
    email_subject: subject,
    email_body_html: `<html><body>${emailBody}${trackingPixel}</body></html>`,
    email_body_plain: body,
    step_number: 1
  }
}];

