const item = $input.first().json;
const nextStep = (item.step_number || 1) + 1;
const summary = [
  `Name: ${item.name}`,
  `Role: ${item.role || 'Professional'}`,
  `Company: ${item.company || 'their company'}`,
  `Previous emails sent: ${item.step_number}`,
  `Follow-up number: ${nextStep}`,
  `About: ${(item.about || '').substring(0, 200)}`
].join('\n');
return [{ json: { ...item, ai_summary: summary, next_step: nextStep } }];

const BACKEND_URL = 'https://email-drip-campaign-hpo2.onrender.com';

const leadData = $('Build Follow-up Context').first().json;

const aiRaw = $('AI Generate Follow-up Email').first().json.content?.parts?.[0]?.text || '';

let parsed = {};

try {
  parsed = JSON.parse(aiRaw);
} catch (e) {
  console.log("Follow-up JSON parse failed");
}

const subject = parsed.subject || `Quick follow-up (${leadData.next_step})`;
const body = parsed.body || aiRaw;

const trackingId = 'trk_fu_' + Date.now() + '_' + Math.random().toString(36).substring(2, 10);

const trackingPixel = `<img src="${BACKEND_URL}/api/tracking/track/${trackingId}" width="1" height="1" style="display:none;" />`;

const urlRegex = /(https?:\/\/[^\s<>"]+)/g;

let emailBody = String(body).replace(urlRegex, (url) => {
  if (url.includes(BACKEND_URL)) return url;

  return `${BACKEND_URL}/api/tracking/click/${trackingId}?redirect_url=${encodeURIComponent(url)}`;
});

// formatting
emailBody = emailBody.replace(/\n/g, '<br>');

return [{
  json: {
    ...leadData,
    tracking_id: trackingId,
    email_subject: subject,
    email_body_html: `<html><body>${emailBody}<br><br>${trackingPixel}</body></html>`,
    email_body_plain: body,
    step_number: leadData.next_step || 1
  }
}];

const emailData = $('Prepare Email with Tracking').first().json;
const leadData = $('Build AI Summary').first().json;

const dbResult = $input.first().json;
const leadId = dbResult.id || dbResult.rows?.[0]?.id;

return [{
  json: {
    ...emailData,
    ...leadData,  
    lead_id: leadId
  }
}];

